import{_ as o,o as t,c as a,ae as r}from"./chunks/framework.BzQXgbNp.js";const g=JSON.parse('{"title":"Minecraft 伺服器迎賓小提示系統 (Welcome Tips System)","description":"","frontmatter":{},"headers":[],"relativePath":"Mc-Welcome-Tips.md","filePath":"Mc-Welcome-Tips.md"}'),s={name:"Mc-Welcome-Tips.md"};function c(i,e,l,n,d,m){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="minecraft-伺服器迎賓小提示系統-welcome-tips-system" tabindex="-1">Minecraft 伺服器迎賓小提示系統 (Welcome Tips System) <a class="header-anchor" href="#minecraft-伺服器迎賓小提示系統-welcome-tips-system" aria-label="Permalink to &quot;Minecraft 伺服器迎賓小提示系統 (Welcome Tips System)&quot;">​</a></h1><h2 id="📌-功能概述" tabindex="-1">📌 功能概述 <a class="header-anchor" href="#📌-功能概述" aria-label="Permalink to &quot;📌 功能概述&quot;">​</a></h2><p>當玩家登入伺服器時，系統會在玩家連線完成 1 秒後，從小提示池中隨機抽樣 1 條發送至玩家的聊天欄中，幫助玩家快速了解與熟悉伺服器的特色指令與系統功能。</p><hr><h2 id="💡-提示池對照表-tips-pool" tabindex="-1">💡 提示池對照表 (Tips Pool) <a class="header-anchor" href="#💡-提示池對照表-tips-pool" aria-label="Permalink to &quot;💡 提示池對照表 (Tips Pool)&quot;">​</a></h2><ol><li><strong>領地與箱子鎖</strong>: <code>🔒 害怕箱子與領地被偷嗎？快來試試 /padlock 鎖箱功能吧！</code></li><li><strong>每日任務系統</strong>: <code>📋 玩膩了？輸入 /tasks 看看今日的每日擊殺與採礦任務吧！</code></li><li><strong>箱子商店交易</strong>: <code>🏪 想當首富嗎？拿著箱子與告示牌輸入 /shop 建立自己的商店吧！</code></li><li><strong>Carpet 假人掛機</strong>: <code>🤖 需要幫忙自動掛機嗎？輸入 /fp &lt;名稱&gt; 召喚專屬假人替你工作！</code></li><li><strong>Discord 官方社群</strong>: <code>🤝 想邀請朋友一起遊玩嗎？輸入 /discord 獲取官方 Discord 邀請連結！</code></li><li><strong>個人家園點設定</strong>: <code>🏠 找不到回家的路嗎？使用 /sethome &lt;名稱&gt; 建立家園，隨時輸入 /home 返回！</code></li><li><strong>公共地標地圖</strong>: <code>🚩 想探索熱門地標或公共設施嗎？輸入 /warp 看看伺服器有哪些地標傳送點！</code></li><li><strong>返回點與死亡點</strong>: <code>💀 剛才不幸意外死亡或傳送錯地方了？輸入 /back 即可瞬間返回上次地點或死亡點！</code></li><li><strong>每日簽到抽獎</strong>: <code>🎁 每天登入別忘了輸入 /checkin 進行簽到，領取連續簽到獎勵與抽獎券！</code></li><li><strong>安全金幣轉帳</strong>: <code>💸 想給好朋友金幣嗎？輸入 /pay &lt;玩家&gt; &lt;金額&gt; 進行安全轉帳！</code></li></ol><hr><h2 id="🛠️-技術實作細節" tabindex="-1">🛠️ 技術實作細節 <a class="header-anchor" href="#🛠️-技術實作細節" aria-label="Permalink to &quot;🛠️ 技術實作細節&quot;">​</a></h2><ul><li><strong>元件位置</strong>: [WelcomeTipManager.java](file:///c:/Users/Yanggu/Documents/craft-core-shop/fabric-mod/src/main/java/com/craftcore/event/WelcomeTipManager.java)</li><li><strong>觸發時機</strong>: 註冊於 <code>ServerPlayConnectionEvents.JOIN</code>，延遲 1000ms 於 Server 主線程安全調用發送 Component。</li></ul>',9)])])}const h=o(s,[["render",c]]);export{g as __pageData,h as default};
